import { BaseState, eventManager, msgBoxManager, newBottombarManager, SlotBottomBarState } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define, { FeaturePosQueueType } from "../Game_Define";
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";
// import protocol from "../Test/ar2pq9Proto.js";
import { REEL_UI_MANAGER_EVENT } from "../Reel/ReelManager";
import { AudioManager } from "../Audio/AudioManager";
import { Define } from "db://astarte-framework/utilis";
import { tools } from "db://astarte-framework/utilis";

export class AwardState extends BaseState
{
    private m_gameView: GameView = null;
    private m_processTick: number = 0;

    /**
     * @ch 現在盤面資訊
     */
    private m_currentPlateInfo: protocol.ar2pq9Proto.IPlateInfo = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public OnEnter()
    {

        log( "OnEnter State : AWARD" );
        this.m_processTick = 0;


        const spinAck = this.m_gameView.SpinAck;
        const winValue = spinAck.RoundQueue[ this.m_gameView.CurRoundIndex ].RoundWin;
        const totalWin = spinAck.TotalWin;



        /**@ch 設定盤面符號不暗 */
        this.m_gameView.SlotReels.SetSymbolDark( false, -1 );

        if ( winValue > 0 && !this.m_gameView.IsGoingToFree )
        {
            this.ProcessFinalAward( winValue,totalWin, false );
        }
    }

    public OnProcess( dt: number )
    {
        if ( this.m_processTick > 0 )
        {
            this.m_processTick -= dt;
            if ( this.m_processTick > 0 ) return;
        }
        if ( this.m_gameView.BigWin.IsEnd )
        {
            this.m_gameView.BigWin.node.active = false;
            this.m_gameView.FadeBgmIn();
            this.m_gameView.AfterShowWin();
        }
    }

    public OnLeave()
    {
        this.m_currentPlateInfo = null;
        this.m_gameView.CanStopBigWin = false;
    }



    /**
     * @ch 處理最後報獎
     * @param totalWin 總贏分
     * @param isNotShowNormalWin 是否不顯示NormalWin
     */
    private ProcessFinalAward(winValue: number, totalWin: number, isNotShowNormalWin: boolean) : void {

        const bet: number = Game_Define.GetNowBetValue();
        const rate = winValue / bet;

        if ( winValue <= 0 ) return;

        // 小獎（倍率 < BigWin 門檻）
        if ( rate < Game_Define.BigWinWinRule.BIG_WIN_MIN )
        {
            if ( isNotShowNormalWin ) return;

            // 小獎音效
            if (rate < 3) {
                AudioManager.Play(AudioManager.AudioClips.Small_Win01);
            } else if (rate < 5) {
                AudioManager.Play(AudioManager.AudioClips.Small_Win02);
            } else {
                AudioManager.Play(AudioManager.AudioClips.Small_Win03);
            }
            this.m_gameView.ShowSmallWinLabel( winValue, Game_Define.SMALLWIN_TIME );
            this.m_processTick = Game_Define.SMALLWIN_TIME;

        }
        // 大獎
        else
        {
            this.m_gameView.SetManualVisible( false );
            let lvl = 0;
            // SUPER >= 50x, MEGA >= 25x, BIG >= 10x
            if ( rate >= Game_Define.BigWinWinRule.SUPER_WIN_MIN )
            {
                lvl = 3; // SUPER
            }
            else if ( rate >= Game_Define.BigWinWinRule.MEGA_WIN_MIN )
            {
                lvl = 2; // MEGA
            }
            else
            {
                lvl = 1; // BIG
            }

            this.m_gameView.ShowBigWin( winValue, lvl );
            this.m_gameView.FadeBgmOut();
            newBottombarManager.SetSpinState( SlotBottomBarState.GET_AWARD_NO_AUTO );

            // 0.5s 延遲保護：防止玩家太快跳過看不到動畫
            this.m_gameView.CanStopBigWin = false;
            Define.Wait( this.m_gameView, 0.5 ).then( () =>
            {
                this.m_gameView.CanStopBigWin = true;
                if ( newBottombarManager.IsAutoSpin )
                {
                    newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_AUTOPLAY_HARDSTOP );
                }
                else
                {
                    newBottombarManager.SetSpinState( SlotBottomBarState.START_SPIN );
                }
            } );
        }
        newBottombarManager.SetWinValueWithCheck( { maxWin: totalWin, value: this.m_gameView.RoundWin } );
    }



    /**@ch 取得Scatter中獎位置
     * @returns Scatter中獎位置
     */
    private GetScatterPositions(): number[] {
        let scatterPositions: number[] = [];

        if (this.m_currentPlateInfo.FeaturePosQueue.length > 0) {
            const featurePosQueue = this.m_currentPlateInfo.FeaturePosQueue[FeaturePosQueueType.Scatter];
            for (let position of featurePosQueue.Data) {
                scatterPositions.push(position);
            }
        }
        return scatterPositions;
    }



    /**
     * @ch 設定Reel黑幕顯示
     * @param isShow 是否顯示
     */
    private SetReelBlackMaskShow(isShow: boolean) {
        eventManager.Dispatch(isShow ? REEL_UI_MANAGER_EVENT.SHOW_BLACK_MASK : REEL_UI_MANAGER_EVENT.HIDE_BLACK_MASK);
    }

    /**
     * @ch 暫停背景音樂
     */
    private PauseBgm() {
        // 暫停背景音樂
        if (this.m_gameView.IsFreeGame) {
            this.m_gameView.PauseFreeGameBgm();
        }
        else {
            this.m_gameView.PauseMainGameBgm();
        }
    }

    /**
     * @ch 恢復背景音樂
     */
    private ResumeBgm() {
        // 恢復背景音樂
        if (this.m_gameView.IsFreeGame) {
            this.m_gameView.ResumeFreeGameBgm();
        }
        else {
            this.m_gameView.ResumeMainGameBgm();
        }
    }



    /**
     * @ch 表演變換Wild Symbol效果
     * @param featureWildData 變換Wild Symbol資料
     */


    /**
     * @ch 表演Bingo Combo音效
     * @param comboCount Combo數量
     */
    private PlayBingoComboSound(comboCount: number) {
        // 假如小於最小值則不播放
        if (comboCount < Game_Define.BINGO_COMBO_MIN_COUNT) {
            return;
        }

        // 假如大於最大值則播放最大值
        if (comboCount > Game_Define.BINGO_COMBO_MAX_COUNT) {
            comboCount = Game_Define.BINGO_COMBO_MAX_COUNT;
        }

        AudioManager.Play(AudioManager.AudioClips[`Bingo_Combo0${comboCount}`]);
    }

    /**
     * @ch 表演MaxFlag MessageBox
     */
    private async PlayMaxFlagMessageBox() : Promise<void> {
        log("PlayMaxFlagMessageBox");
        return new Promise<void>((resolve) => {
            msgBoxManager.ShowMessageBox(
                Define.StringKey.MSGBOX_MAX_REWARD,
                Define.StringKey.MSGBOX_TITLE_SYSTEM_INFO,
                () => {
                    resolve();
                }
            );
        });
    }
}

