import { log } from "cc";
import { BaseState, SlotBottomBarState, commonGameManager, newBottombarManager, newExtraManager, stateManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import { roundController, tempoSetting, tools, CommonState } from "db://astarte-framework/utilis";

export class RoundEndState extends BaseState
{
    private m_gameView: GameView = null;
    private m_processTick: number = 0;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public OnEnter()
    {

        log( "OnEnter State : ROUND_END" );
        const isNoWin = this.m_gameView.RoundInfo.RoundWin === 0;

        // 不是FG的話要歸零
        if (this.m_gameView.CurRoundIndex + 1 >= this.m_gameView.SpinAck.RoundQueue.length)
        {
            // 盤面Index回復
            this.m_gameView.CurRoundIndex = -1;

            if ( newExtraManager.IsFeaturesDemoMode )
            {
                newExtraManager.CheckBuyBonusOverAni();
                this.m_gameView.ClearAll();
            }
        }



        this.m_gameView.CanSpaceStop = false;
        this.m_processTick = 0;
        this.m_gameView.RetryRoundEnd();

        // 轉輪節奏模組：海盜女王
        let tempoModule = tempoSetting.TempoSetting.PirateQueen;
        if ( !newBottombarManager.IsHardStop )
        {
            if ( this.m_gameView.IsFreeGame )
            {
                if ( !isNoWin )
                {
                    this.m_processTick = tempoModule.HAS_ROUND_WIN.true;
                }
                else
                {
                    this.m_processTick = tempoModule.HAS_ROUND_WIN.false.IN_FG;
                }
            }
            else
            {
                if ( !isNoWin )
                {
                    this.m_processTick = tempoModule.HAS_ROUND_WIN.true;
                }
                else
                {
                    this.m_processTick = tempoModule.HAS_ROUND_WIN.false.IN_MG;
                }
            }
        }
    }

    public OnProcess( dt: number )
    {
        this.m_processTick = tools.strip( this.m_processTick - dt );
        if ( this.m_processTick > 0
            || !roundController.CanToNextRound()
            || ( commonGameManager.IsTwice && !commonGameManager.IsGetRoundEndAck ) )
        {
            return;
        }

        // 離開特色，要將自動玩關閉
        if ( newExtraManager.IsFeaturesDemoMode && !newBottombarManager.IsAutoSpin )
        {
            newBottombarManager.ShowAutoPlayState( false );
            this.m_gameView.EffectPlate.CurAwardLines.length = 0;
        }

        // 確認有無自動玩次數 要改變地bar顯示
        if ( newBottombarManager.IsAutoSpin && newBottombarManager.IsAutoPlayByTimes() )
        {
            newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_STOP_IN_AUTOPLAY );
        }

        this.m_gameView.ForEndToNext();


    }

    public OnLeave()
    {

    }
}

