23	    {
24	
25	        log( "OnEnter State : COUNT_MULT" );
26	        let plateInfoData = this.m_gameView.SpinAck.RoundQueue[ this.m_gameView.CurRoundIndex ].PlateQueue;
27	        let plateIdx = this.m_gameView.CurPlateIndex;
28	        if(plateIdx < plateInfoData.length )
29	        {
30	            let awardDataVec = plateInfoData[ plateIdx ].AwardDataVec ? plateInfoData[ plateIdx ].AwardDataVec : [];
31	
32	            let explodeDataVec: protocol.ar2pq9Proto.IAwardData[] = [];
33	            let targetDataVec: protocol.ar2pq9Proto.IAwardData[] = [];
34	            //加入標靶消除範圍
35	            if(plateInfoData[plateIdx].TargetDataVec.length > 0)
36	            {
37	                for(let i = 0; i < plateInfoData[plateIdx].TargetDataVec.length; i++)
