42	                        eliminatePos.push(pos);
43	                    }
44	
45	                    //標靶消除範圍
46	                    explodeDataVec.push( {
47	                        Symbol: plateInfoData[plateIdx].TargetDataVec[i].Symbol,
48	                        EliminatePos: eliminatePos
49	                    } );
50	
51	                    //標靶演出用
52	                    targetDataVec.push( {
53	                        Symbol: plateInfoData[plateIdx].TargetDataVec[i].Symbol,
54	                        EliminatePos: [plateInfoData[plateIdx].TargetDataVec[i].Pos]
55	                    } );
56	                }
57	            }
58	
59	            for ( let i = 0; i < awardDataVec.length; i++ )
60	            {
61	                if(awardDataVec[i].EliminatePos.length > 0)
62	                {
63	                    explodeDataVec.push( awardDataVec[ i ] );
64	                    
65	                }
66	            }
67	            this.m_gameView.CurExplodeDataVec = explodeDataVec;
68	
69	       
70	
71	            // 計算乘倍
72	            let promises: Promise<void>[] = [];
73	            this.m_gameView.PendingAwardResults = [];
74	            for ( let i = 0; i < awardDataVec.length; i++ )
75	            {
76	                let awardData : protocol.ar2pq9Proto.IAwardData[] = [];
77	                awardData.push(awardDataVec[i]);
78	
79	                //贏分演出（有乘倍時保持壓暗）
80	                const hasMult = awardDataVec[i].Multiple > 1;
81	                if (i === 0) {
82	                    const comboCount = Math.min(plateIdx + 1, 5);
83	                    const suffix = this.m_gameView.IsFreeGame ? '_F' : '';
84	                    AudioManager.Play(AudioManager.AudioClips[`Combo_0${comboCount}${suffix}`]);
85	                }
86	
87	                let col = Math.floor(awardDataVec[i].EliminatePos[0] / Game_Define.ROW);
88	                let isLeft = col < Game_Define.COL / 2;
89	                let pos0 = awardDataVec[i].EliminatePos[0];
90	
91	                if (awardDataVec[i].Multiple > 1) {
92	                    // 1. 顯示 ODD*Bet 與 SymbolWinEffect 同時
93	                    let bet = Game_Define.GetNowBetValue();
94	                    let oddsValue = tools.times(awardDataVec[i].Odds, bet);
95	                    let [, oddsNode] = await Promise.all([
96	                        this.m_gameView.EffectPlate.SymbolWinEffect(awardData, hasMult),
97	                        this.m_gameView.EffectPlate.ShowStaticOdds(pos0, oddsValue.toString(), isLeft)
98	                    ]);
99	
100	                    // 2. 乘倍飛入（飛到 odds 文字後方）
101	                    const oddsLabel = oddsNode.getComponentInChildren(Label);
