106	                        targetPos = oddsLabel.node.getWorldPosition();
107	                        targetPos.x += halfW + 30;
108	                    }
109	                    // 乘倍飛到 odd（角色+砲台+音效已移除）
110	                    for(let pos of awardDataVec[i].EliminatePos)
111	                    {
112	                        promises.push( new Promise(
113	                            async ( resolve ) =>
114	                            {
115	                                eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.POP_MULITEM, pos, 
116	                                    this.m_gameView.EffectPlate.GetEffctNode(Game_Define.LAYERS.MULTI_FLY) );
117	                                let waitTime = this.m_gameView.IsHardStop ? 0 : 0.2;
118	                                await Define.Wait( this.m_gameView, waitTime );
119	                                eventManager.Dispatch( MULTIPLIER_BASE_MANAGER_EVENT.MULITEM_FLY_TO_TARGET, pos, 
