148	                }
149	                else {
150	                    // 最後一筆無乘倍 award 時提前播砲台動畫（非阻塞）
151	                    if (i === awardDataVec.length - 1) {
152	                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, 
153	                            CHARACTER_ANIM_NAME.Symbol_Remove, false, () => {});
154	                        eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON, 
155	                            CANNON_ANIM_NAME.Symbol_Remove, false, () => {});
156	                    }
157	                    await this.m_gameView.EffectPlate.SymbolWinEffect(awardData, hasMult);
158	                }
159	
160	                // 4. 暫存結果（EXPLODE 時顯示）
161	                let bet = Game_Define.GetNowBetValue();
162	                let winValue = awardDataVec[i].Win || tools.times(awardDataVec[i].Odds || 0, bet);
163	                let winDisplay = winValue.toString();
