166	                    pos: pos0,
167	                    win: winValue,
168	                    fullResult: winDisplay,
169	                    isLeft: isLeft
170	                });
171	
172	            }
173	
174	            //標靶演出
175	            if(targetDataVec.length > 0)
176	            {
177	                await Define.Wait( this.m_gameView, 0.5 );
178	                // 標靶演出開始 0.5s 後播砲台動畫（非阻塞）
