185	                const isExpanded = this.m_gameView.IsFreeGame && this.m_gameView.FreePickItems.indexOf(0) >= 0;
186	                await this.m_gameView.EffectPlate.PlayTargetExplodeEffect(
187	                    plateInfoData[plateIdx].TargetDataVec, isExpanded);
188	            }
189	            
190	            
191	
192	            
193	       
194	            stateManager.NextState( Game_Define.GameState.EXPLODE );
195	        }
196	        else
197	        {
198	            stateManager.NextState( Game_Define.GameState.EFFECT_START );
199	        }
200	
201	        
202	    }
203	
204	    public OnProcess()
205	    {
206	
207	    }
208	
209	    public OnLeave()
210	    {
211	
212	    }
213	}

