ClickSpin() {
    AudioManager.Play(AudioManager.AudioClips.Spin);

    //按下開始按鍵
    if (stateManager.Current() !== CommonState.IDLE || newExtraManager.IsNowInDemoMenu) {
        return;
    }

    const nowChips = tools.strip(newBottombarManager.GetChips());
    const nowBetValue = tools.strip(newBottombarManager.GetNowBetValue());

    const isExtraOn = this.m_extraBetComp?.IsExtra ?? false;
    const isFreePlay = newBottombarManager.IsFreeSpin || this.IsFreeGame;
    const hasEnoughForExtraBet = !isExtraOn || isFreePlay ||
        nowChips >= tools.strip(newBottombarManager.GetRealBetValue());

    if (
        (
            (this.m_buyBonus && nowChips >= this.m_buyBonus?.GetBuyBonusBet())
            || (!this.m_buyBonus && nowChips >= nowBetValue) // 若無BuyBonus，則判斷現金是否足夠，通常遊戲都會有BuyBonus，所以這裡通常不會進入
            || newBottombarManager.IsFreeSpin
            || this.IsFreeGame
        )
        && hasEnoughForExtraBet
        && backpackManager.IsBackpackPass()
        && !giftCodeManager.IsOpen()
    ) {
        newBottombarManager.SetSpinState(SlotBottomBarState.CLICK_SPIN);
        this.m_buyBonus?.Hide();
        this.m_extraBetComp?.OnSpin();
        eventManager.Dispatch(CommonEventName.SpinReqNotify);
    }
    else {
        this.m_buyBonus?.CleanInfo();
        if (backpackManager.IsBackpackPass() && !giftCodeManager.IsOpen()) {
            let betList = newBottombarManager.GetBetList();
            if (
                nowBetValue === tools.strip(betList[0])
                || newBottombarManager.GetChips() < tools.strip(betList[0])
            ) {
                msgBoxManager.ShowMessageBox(Define.StringKey.MSGBOX_MONEY_NOT_ENOUGH);
            }
            else {
                msgBoxManager.ShowMessageBox(Define.StringKey.MSGBOX_MONEY_NOT_ENOUGH_DOWN_BET);
            }
        }
        else {
            newBottombarManager.SetSpinState(SlotBottomBarState.IDLE);
            stateManager.NextState(CommonState.IDLE);
        }
    }
}

