async ExtendShowBar( goToExtend: boolean )
{
    if ( !this.m_canExtend ||
        tools.CheckSwitchOff( SwitchOffKeyDefine.CloseExtraBet ) )
    {
        return;
    }
    if ( newBottombarManager && !this.m_ExtraBetAniPlaying )
    {
        if ( goToExtend )
        {
            if ( !newBottombarManager.IsAutoSpin && !Define.IsUsingItem
                && !buyBonusManager.IsBuyBonus )
            {
                if ( !this.m_isExtendShowBar )
                {
                    this.m_isExtendShowBar = true;
                    newBottombarManager.SetSpinState( SlotBottomBarState.CLICK_SPIN );
                    this.m_ExtraBetAniPlaying = true;
                    if ( this.m_multiExtraBetNode )
